mapper.select:
SELECT cri.category_id, cri.category_name, COUNT(cri.id) as item_count, SUM(cri.deduct_score) as total_deduct, COUNT(DISTINCT ccs.class_id) as affected_class_count FROM check_record_items cri LEFT JOIN check_record_class_stats ccs ON cri.class_stat_id = ccs.id AND ccs.deleted = 0 WHERE cri.deleted = 0 AND cri.record_id = #{recordId}
AND ccs.class_id = #{classId}
GROUP BY cri.category_id, cri.category_name ORDER BY total_deduct ASC

SELECT cri.item_id, cri.item_name, cri.category_id, cri.category_name, COUNT(cri.id) as deduct_count, SUM(cri.deduct_score) as total_deduct, COUNT(DISTINCT ccs.class_id) as affected_class_count, AVG(cri.deduct_score) as avg_deduct FROM check_record_items cri LEFT JOIN check_record_class_stats ccs ON cri.class_stat_id = ccs.id AND ccs.deleted = 0 WHERE cri.deleted = 0 AND cri.record_id = #{recordId}
AND cri.category_id = #{categoryId}
GROUP BY cri.item_id, cri.item_name, cri.category_id, cri.category_name ORDER BY total_deduct ASC

SELECT COUNT(*)
FROM check_record_items cri
LEFT JOIN check_record_class_stats ccs ON cri.class_stat_id = ccs.id AND ccs.deleted = 0
WHERE cri.deleted = 0
AND cri.record_id = #{recordId}
AND ccs.class_id = #{classId}
